#include <bits/stdc++.h>
using namespace std;

const int N=1e6+6;

int n,nxt[N],f[N];
char s[N];
long long ans;

int main(){
	//freopen("P3435_1.in","r",stdin);
	scanf("%d%s",&n,s+1);
	nxt[1]=0;
	for(int i=2,j=0;i<=n;i++){
		while(j && s[i]!=s[j+1])
			j=nxt[j];
		if(s[i]==s[j+1])
			j++;
		nxt[i]=j;
	}
	for(int i=1;i<=n;i++){
		if(!nxt[i])
			f[i]=i;
		else
			f[i]=f[nxt[i]];
		ans+=i-f[i];
	}
	printf("%lld",ans);
	return 0;
}
